--liquibase formatted sql

--changeset hospital-service:094-doctors-real-seed
--comment: Remove dummy doctors and seed real doctors from DrInfo.xlsx (deduplicated by latest record per doctor code)

DELETE FROM hospital.doctors
WHERE doctor_code LIKE 'TEST-DOC-%';

WITH real_doctors(
    doctor_code,
    doctor_name,
    dept_name,
    doctor_type,
    indoor_outdoor_status,
    degree,
    speciality,
    gender,
    birth_date,
    registration_date,
    bmdc_registration_number,
    phone_number,
    email,
    visit_fee_new,
    visit_fee_old,
    prescription_status,
    availability_status,
    is_active,
    sms_enabled,
    patients_per_day,
    serial_start_from,
    number_of_days_can_appointment,
    appointments_from_web,
    appointments_from_mobile,
    chamber_room,
    created_by
) AS (
