INSERT INTO hospital.doctors (
    doctor_code,
    doctor_name,
    department_id,
    doctor_type,
    indoor_outdoor_status,
    degree,
    speciality,
    gender,
    birth_date,
    registration_date,
    bmdc_registration_number,
    phone_number,
    email,
    visit_fee_new,
    visit_fee_old,
    prescription_status,
    availability_status,
    is_active,
    sms_enabled,
    patients_per_day,
    serial_start_from,
    number_of_days_can_appointment,
    appointments_from_web,
    appointments_from_mobile,
    chamber_room,
    created_by
)
SELECT
    rd.doctor_code,
    rd.doctor_name,
    dd.department_id,
    rd.doctor_type,
    rd.indoor_outdoor_status,
    rd.degree,
    rd.speciality,
    rd.gender,
    rd.birth_date,
    rd.registration_date,
    rd.bmdc_registration_number,
    rd.phone_number,
    rd.email,
    rd.visit_fee_new,
    rd.visit_fee_old,
    rd.prescription_status,
    rd.availability_status,
    rd.is_active,
    rd.sms_enabled,
    rd.patients_per_day,
    rd.serial_start_from,
    rd.number_of_days_can_appointment,
    rd.appointments_from_web,
    rd.appointments_from_mobile,
    rd.chamber_room,
    rd.created_by
FROM real_doctors rd
JOIN hospital.doctor_departments dd ON dd.department_name = rd.dept_name
ON CONFLICT (doctor_code) DO UPDATE
SET
    doctor_name = EXCLUDED.doctor_name,
    department_id = EXCLUDED.department_id,
    doctor_type = EXCLUDED.doctor_type,
    indoor_outdoor_status = EXCLUDED.indoor_outdoor_status,
    degree = EXCLUDED.degree,
    speciality = EXCLUDED.speciality,
    gender = EXCLUDED.gender,
    birth_date = EXCLUDED.birth_date,
    registration_date = EXCLUDED.registration_date,
    bmdc_registration_number = EXCLUDED.bmdc_registration_number,
    phone_number = EXCLUDED.phone_number,
    email = EXCLUDED.email,
    visit_fee_new = EXCLUDED.visit_fee_new,
    visit_fee_old = EXCLUDED.visit_fee_old,
    prescription_status = EXCLUDED.prescription_status,
    availability_status = EXCLUDED.availability_status,
    is_active = EXCLUDED.is_active,
    sms_enabled = EXCLUDED.sms_enabled,
    patients_per_day = EXCLUDED.patients_per_day,
    serial_start_from = EXCLUDED.serial_start_from,
    number_of_days_can_appointment = EXCLUDED.number_of_days_can_appointment,
    appointments_from_web = EXCLUDED.appointments_from_web,
    appointments_from_mobile = EXCLUDED.appointments_from_mobile,
    chamber_room = EXCLUDED.chamber_room,
    updated_at = CURRENT_TIMESTAMP,
    updated_by = 'system-import';
